import React, { useState } from 'react';
import axios from 'axios';

export default function Login() {
  // 1. User enter panra email and password-ah store panna State hooks
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [loading, setLoading] = useState(false);

  // 2. Form submit pannum pothu backend-ku data anuppura function
  const handleSubmit = async (e) => {
    e.preventDefault(); // Page refresh aagatha maari thadukka
    setLoading(true);

    try {
      // Backend definition-la /api/users prefix irunthaal intha URL correct
      const response = await axios.post("http://localhost:5000/api/users/login", {
        email: email,
        password: password
      });

      console.log("Login Success:", response.data);
      alert("✅ Welcome to Truck Load Board!");
      // Inga neenga successful login-ku apparam Dashboard-ku navigate pannalam
      
    } catch (error) {
      console.error("Login Error:", error.response?.data || error.message);
      alert("❌ Login Failed: " + (error.response?.data?.message || "Server error"));
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-truckYellow">
      <div className="bg-white p-10 rounded-2xl border-8 border-truckRed shadow-2xl w-96">
        <h2 className="text-4xl font-black text-truckRed text-center mb-6 italic uppercase">
          Login
        </h2>
        
        <form onSubmit={handleSubmit}>
          {/* Email Input */}
          <div className="mb-4">
            <input 
              type="email" 
              placeholder="Email" 
              required
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full p-3 border-2 border-truckYellow rounded font-bold outline-none focus:border-truckRed transition-colors" 
            />
          </div>
          
          {/* Password Input */}
          <div className="mb-6">
            <input 
              type="password" 
              placeholder="Password" 
              required
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className="w-full p-3 border-2 border-truckYellow rounded font-bold outline-none focus:border-truckRed transition-colors" 
            />
          </div>
          
          {/* Submit Button */}
          <button 
            type="submit"
            disabled={loading}
            className="w-full bg-truckRed text-white py-3 rounded-xl font-black uppercase tracking-widest hover:bg-red-700 transition-all active:scale-95 disabled:bg-gray-400"
          >
            {loading ? "Connecting..." : "Enter Board"}
          </button>
        </form>
        
        <p className="mt-4 text-center font-bold text-gray-600 text-sm">
          New here? <span className="text-truckRed cursor-pointer hover:underline">Create Account</span>
        </p>
      </div>
    </div>
  );
}
